    import_body_metrics_hint: '\u05D9\u05D9\u05D1\u05D0 \u05D9\u05D9\u05E6\u05D5\u05D0 Apple Health \u05E9\u05DB\u05D5\u05DC\u05DC \u05E0\u05EA\u05D5\u05E0\u05D9 \u05DE\u05E9\u05E7\u05DC \u05D7\u05DB\u05DD.',
    info_weight: '**\u05DE\u05E9\u05E7\u05DC \u05D2\u05D5\u05E3 \u05DB\u05D5\u05DC\u05DC**\n\u05DB\u05D5\u05DC\u05DC \u05E9\u05E8\u05D9\u05E8, \u05E9\u05D5\u05DE\u05DF, \u05E2\u05E6\u05DE\u05D5\u05EA, \u05DE\u05D9\u05DD \u05D5\u05D0\u05D9\u05D1\u05E8\u05D9\u05DD.\n\n**\u05D0\u05D6\u05D5\u05E8 \u05D9\u05E8\u05D5\u05E7**: BMI \u05EA\u05E7\u05D9\u05DF (18.5-25) \u05DC\u05D2\u05D5\u05D1\u05D4 180 \u05E1\u05F4\u05DE.\n\u05DE\u05E7\u05D5\u05E8: \u05D0\u05E8\u05D2\u05D5\u05DF \u05D4\u05D1\u05E8\u05D9\u05D0\u05D5\u05EA \u05D4\u05E2\u05D5\u05DC\u05DE\u05D9 (WHO).',
    info_body_fat: '**\u05D0\u05D7\u05D5\u05D6 \u05E9\u05D5\u05DE\u05DF \u05D2\u05D5\u05E3**\n\u05D0\u05D7\u05D5\u05D6 \u05D4\u05DE\u05E9\u05E7\u05DC \u05D4\u05DB\u05D5\u05DC\u05DC \u05E9\u05D4\u05D5\u05D0 \u05E9\u05D5\u05DE\u05DF.\n\n**\u05D0\u05D6\u05D5\u05E8 \u05D9\u05E8\u05D5\u05E7**: \u05E7\u05D8\u05D2\u05D5\u05E8\u05D9\u05D9\u05EA \u05E1\u05E4\u05D5\u05E8\u05D8\u05D0\u05D9\u05DD \u05DC\u05D2\u05D1\u05E8\u05D9\u05DD (ACE).\n**\u05D7\u05D9\u05D5\u05E0\u05D9**: 2-5%\n**\u05E1\u05E4\u05D5\u05E8\u05D8\u05D0\u05D9\u05DD**: 6-13%\n**\u05DB\u05D5\u05E9\u05E8**: 14-17%\n**\u05DE\u05DE\u05D5\u05E6\u05E2**: 18-24%\n**\u05D4\u05E9\u05DE\u05E0\u05D4**: 25%+\n\u05DE\u05E7\u05D5\u05E8: American Council on Exercise (ACE).',
    info_bmi: '**\u05DE\u05D3\u05D3 \u05DE\u05E1\u05EA \u05D2\u05D5\u05E3 (BMI)**\n\u05E0\u05D5\u05E1\u05D7\u05D4: \u05DE\u05E9\u05E7\u05DC(kg) / \u05D2\u05D5\u05D1\u05D4(m)^2\n\n**\u05D0\u05D6\u05D5\u05E8 \u05D9\u05E8\u05D5\u05E7**: \u05D8\u05D5\u05D5\u05D7 \u05EA\u05E7\u05D9\u05DF WHO.\n**<18.5**: \u05EA\u05EA-\u05DE\u05E9\u05E7\u05DC\n**18.5-25**: \u05EA\u05E7\u05D9\u05DF\n**25-30**: \u05E2\u05D5\u05D3\u05E3 \u05DE\u05E9\u05E7\u05DC\n**30+**: \u05D4\u05E9\u05DE\u05E0\u05D4\n\u05DE\u05E7\u05D5\u05E8: WHO.',
    info_lean_mass: '**\u05DE\u05E1\u05EA \u05D2\u05D5\u05E3 \u05E8\u05D6\u05D4 (LBM)**\n\u05DE\u05E9\u05E7\u05DC \u05DB\u05D5\u05DC\u05DC \u05E4\u05D7\u05D5\u05EA \u05E9\u05D5\u05DE\u05DF.\n\u05DB\u05D5\u05DC\u05DC: **\u05E9\u05E8\u05D9\u05E8\u05D9\u05DD, \u05E2\u05E6\u05DE\u05D5\u05EA, \u05DE\u05D9\u05DD, \u05D0\u05D9\u05D1\u05E8\u05D9\u05DD**.\n\n**\u05D0\u05D6\u05D5\u05E8 \u05D9\u05E8\u05D5\u05E7**: \u05D4\u05DE\u05E9\u05E7\u05DC \u05E9\u05DC\u05DA \u05D1\u05D0\u05D7\u05D5\u05D6 \u05E9\u05D5\u05DE\u05DF \u05E1\u05E4\u05D5\u05E8\u05D8\u05D0\u05D9 (6-13%).\n**\u05E0\u05D5\u05E1\u05D7\u05D4**: LBM = \u05DE\u05E9\u05E7\u05DC x (1 - \u05D0\u05D7\u05D5\u05D6 \u05E9\u05D5\u05DE\u05DF %)\n\u05DC\u05D0 \u05D6\u05D4\u05D4 \u05DC\u05DE\u05E1\u05EA \u05E9\u05E8\u05D9\u05E8 \u2014 \u05DB\u05D5\u05DC\u05DC \u05E2\u05E6\u05DE\u05D5\u05EA (~3 \u05E7\u05F4\u05D2), \u05DE\u05D9\u05DD, \u05D0\u05D9\u05D1\u05E8\u05D9\u05DD.',
    info_muscle_mass: '**\u05DE\u05E1\u05EA \u05E9\u05E8\u05D9\u05E8**\n\u05D0\u05D5\u05DE\u05D3\u05DF \u05DE\u05E9\u05E7\u05DC \u05E9\u05E8\u05D9\u05E8 \u05E9\u05DC\u05D3 (BIA).\n\n**\u05D0\u05D6\u05D5\u05E8 \u05D9\u05E8\u05D5\u05E7**: \u05D8\u05D5\u05D5\u05D7 \u05EA\u05E7\u05E0\u05D9 BIA \u05DC\u05D2\u05D1\u05E8\u05D9\u05DD (49-59% \u05DE\u05DE\u05E9\u05E7\u05DC \u05D4\u05D2\u05D5\u05E3).\n\u05D4\u05E6\u05DC\u05D1\u05D4: \u05D4\u05DE\u05E9\u05E7\u05DC \u05E9\u05DC\u05DA \u05D3\u05D9\u05E8\u05D2 35.0 \u05E7\u05F4\u05D2 (52.8%) \u05DB-"Standard".\n\u05DC\u05D0 \u05DE\u05D9\u05D5\u05E6\u05D0 \u05DC-Apple Health \u2014 \u05DE\u05D5\u05E4\u05E7 \u05DE\u05E6\u05D9\u05DC\u05D5\u05DE\u05D9 \u05DE\u05E1\u05DA \u05D0\u05E4\u05DC\u05D9\u05E7\u05E6\u05D9\u05D9\u05EA \u05D4\u05DE\u05E9\u05E7\u05DC.',
    info_muscle_rate: '**\u05D0\u05D7\u05D5\u05D6 \u05E9\u05E8\u05D9\u05E8**\n\u05DE\u05E1\u05EA \u05E9\u05E8\u05D9\u05E8 \u05DB\u05D0\u05D7\u05D5\u05D6 \u05DE\u05DE\u05E9\u05E7\u05DC \u05D4\u05D2\u05D5\u05E3.\n\u05E0\u05D5\u05E1\u05D7\u05D4: \u05DE\u05E1\u05EA \u05E9\u05E8\u05D9\u05E8 / \u05DE\u05E9\u05E7\u05DC x 100.\n\n**\u05D0\u05D6\u05D5\u05E8 \u05D9\u05E8\u05D5\u05E7**: \u05EA\u05E7\u05E0\u05D9 BIA \u05DC\u05D2\u05D1\u05E8\u05D9\u05DD: 49-59%.\n\u05D4\u05E6\u05DC\u05D1\u05D4: \u05D4\u05DE\u05E9\u05E7\u05DC \u05E9\u05DC\u05DA \u05D3\u05D9\u05E8\u05D2 53.0% \u05DB-"Standard".\n**\u05E0\u05DE\u05D5\u05DA**: <49% | **\u05EA\u05E7\u05E0\u05D9**: 49-59% | **\u05D2\u05D1\u05D5\u05D4**: >59%',

