    delete_plan: '\u05DE\u05D7\u05E7 \u05D0\u05D9\u05DE\u05D5\u05DF \u05DE\u05EA\u05D5\u05DB\u05E0\u05DF',
    delete_plan_confirm: '\u05D1\u05D8\u05D5\u05D7 \u05E9\u05D1\u05E8\u05E6\u05D5\u05E0\u05DA \u05DC\u05DE\u05D7\u05D5\u05E7 \u05D0\u05D9\u05DE\u05D5\u05DF \u05DE\u05EA\u05D5\u05DB\u05E0\u05DF \u05D6\u05D4?',
    plan_add_workout: '\u05D4\u05D5\u05E1\u05E3 \u05D0\u05D9\u05DE\u05D5\u05DF',
    plan_phase_build: '\u05D1\u05E0\u05D9\u05D9\u05D4',
