    plan_phase_peak: '\u05E9\u05D9\u05D0',
    plan_phase_taper: '\u05D4\u05E4\u05D7\u05EA\u05D4',
    info_phase_mid: '**\u05E9\u05DC\u05D1 \u05D1\u05D9\u05E0\u05D9\u05D9\u05DD**\n\u05DE\u05E2\u05D1\u05E8 \u05DE\u05D1\u05E0\u05D9\u05D9\u05EA \u05D1\u05E1\u05D9\u05E1 \u05DC\u05E2\u05D1\u05D5\u05D3\u05D4 \u05E1\u05E4\u05E6\u05D9\u05E4\u05D9\u05EA \u05DC\u05DE\u05E8\u05D5\u05E5.\n\u05E9\u05DE\u05D9\u05E8\u05EA \u05E0\u05E4\u05D7, \u05D4\u05E2\u05DC\u05D0\u05EA \u05E2\u05D5\u05E6\u05DE\u05D4 \u05D4\u05D3\u05E8\u05D2\u05EA\u05D9\u05EA.\n\n**\u05D9\u05E2\u05D3 \u05E1\u05D9\u05D1\u05D5\u05DC\u05EA**: \u05D4\u05D5\u05E1\u05E4\u05EA \u05D0\u05D9\u05DE\u05D5\u05E0\u05D9 \u05D8\u05DE\u05E4\u05D5 \u05D5\u05E1\u05E3.\n**\u05D1\u05E0\u05D9\u05D9\u05EA \u05E9\u05E8\u05D9\u05E8**: \u05DE\u05E2\u05D1\u05E8 \u05DE\u05D4\u05D9\u05E4\u05E8\u05D8\u05E8\u05D5\u05E4\u05D9\u05D4 \u05DC\u05DB\u05D5\u05D7/\u05E2\u05D5\u05E6\u05DE\u05D4.\n**\u05D9\u05E8\u05D9\u05D3\u05EA \u05DE\u05E9\u05E7\u05DC**: \u05D4\u05D3\u05E7 \u05D2\u05D9\u05E8\u05E2\u05D5\u05DF \u2014 \u05D4\u05E8\u05DB\u05D1 \u05D2\u05D5\u05E3 \u05E6\u05E8\u05D9\u05DA \u05DC\u05D4\u05D9\u05D5\u05EA \u05E7\u05E8\u05D5\u05D1 \u05DC\u05D9\u05E2\u05D3.',
    info_phase_build: '**\u05E9\u05DC\u05D1 \u05D1\u05E0\u05D9\u05D9\u05D4**\n\u05E2\u05DC\u05D9\u05D9\u05EA \u05E0\u05E4\u05D7 \u05D5\u05E2\u05D5\u05E6\u05DE\u05D4 \u05D4\u05D3\u05E8\u05D2\u05EA\u05D9\u05EA.\n\u05D3\u05D2\u05E9 \u05E2\u05DC \u05D1\u05E1\u05D9\u05E1 \u05D0\u05D9\u05E8\u05D5\u05D1\u05D9 \u05D5\u05D8\u05DB\u05E0\u05D9\u05E7\u05D4.\n\n**\u05D9\u05E2\u05D3 \u05E1\u05D9\u05D1\u05D5\u05DC\u05EA**: \u05D0\u05D9\u05DE\u05D5\u05E0\u05D9\u05DD \u05D0\u05E8\u05D5\u05DB\u05D9\u05DD, \u05E2\u05DC\u05D9\u05D9\u05EA \u05E0\u05E4\u05D7 5-10% \u05D1\u05E9\u05D1\u05D5\u05E2.\n**\u05D1\u05E0\u05D9\u05D9\u05EA \u05E9\u05E8\u05D9\u05E8**: \u05DB\u05D5\u05D7 3 \u05E4\u05E2\u05DE\u05D9\u05DD/\u05E9\u05D1\u05D5\u05E2 + \u05D0\u05D9\u05DE\u05D5\u05E0\u05D9\u05DD \u05E1\u05E4\u05E6\u05D9\u05E4\u05D9\u05D9\u05DD.\n**\u05D9\u05E8\u05D9\u05D3\u05EA \u05DE\u05E9\u05E7\u05DC**: \u05D2\u05D9\u05E8\u05E2\u05D5\u05DF \u05DE\u05EA\u05D5\u05DF, \u05E0\u05E4\u05D7 \u05D2\u05D1\u05D5\u05D4 \u05D1\u05E2\u05D5\u05E6\u05DE\u05D4 \u05E0\u05DE\u05D5\u05DB\u05D4.',
    info_phase_peak: '**\u05E9\u05DC\u05D1 \u05E9\u05D9\u05D0 (2-4 \u05E9\u05D1\u05D5\u05E2\u05D5\u05EA \u05DC\u05E4\u05E0\u05D9 \u05D4\u05DE\u05E8\u05D5\u05E5)**\n\u05E2\u05D5\u05DE\u05E1 \u05D0\u05D9\u05DE\u05D5\u05DF \u05DE\u05E7\u05E1\u05D9\u05DE\u05DC\u05D9.\n\u05D0\u05D9\u05DE\u05D5\u05E0\u05D9\u05DD \u05DE\u05E4\u05EA\u05D7 \u05D1\u05E2\u05D5\u05E6\u05DE\u05EA \u05DE\u05E8\u05D5\u05E5.\n\n**\u05D9\u05E2\u05D3 \u05E1\u05D9\u05D1\u05D5\u05DC\u05EA**: \u05D0\u05D9\u05E0\u05D8\u05E8\u05D5\u05D5\u05DC\u05D9\u05DD \u05D1\u05E7\u05E6\u05D1 \u05DE\u05E8\u05D5\u05E5, \u05D0\u05D9\u05DE\u05D5\u05E0\u05D9 \u05D1\u05E8\u05D9\u05E7.\n**\u05D1\u05E0\u05D9\u05D9\u05EA \u05E9\u05E8\u05D9\u05E8**: \u05EA\u05D7\u05D6\u05D5\u05E7\u05D4, \u05DE\u05E2\u05D1\u05E8 \u05DC\u05E2\u05D5\u05E6\u05DE\u05D4.\n**\u05D9\u05E8\u05D9\u05D3\u05EA \u05DE\u05E9\u05E7\u05DC**: \u05DC\u05D0 \u05DC\u05D4\u05D9\u05D5\u05EA \u05D1\u05D2\u05D9\u05E8\u05E2\u05D5\u05DF \u2014 \u05DC\u05EA\u05D3\u05DC\u05E7 \u05D1\u05D9\u05E6\u05D5\u05E2\u05D9\u05DD.',
    info_phase_taper: '**\u05E9\u05DC\u05D1 \u05D4\u05E4\u05D7\u05EA\u05D4 (\u05E9\u05D1\u05D5\u05E2\u05D9\u05D9\u05DD \u05D0\u05D7\u05E8\u05D5\u05E0\u05D9\u05DD)**\n\u05D4\u05E4\u05D7\u05EA\u05EA \u05E0\u05E4\u05D7, \u05E9\u05DE\u05D9\u05E8\u05D4 \u05E2\u05DC \u05E2\u05D5\u05E6\u05DE\u05D4.\n\u05DE\u05E0\u05D5\u05D7\u05D4 \u05D5\u05D7\u05D9\u05D3\u05D5\u05D3 \u05DC\u05DE\u05E8\u05D5\u05E5.\n\n**\u05D9\u05E2\u05D3 \u05E1\u05D9\u05D1\u05D5\u05DC\u05EA**: \u05D4\u05E4\u05D7\u05EA\u05EA \u05E0\u05E4\u05D7 40-60%, 1-2 \u05D0\u05D9\u05DE\u05D5\u05E0\u05D9\u05DD \u05D7\u05D3\u05D9\u05DD.\n**\u05D1\u05E0\u05D9\u05D9\u05EA \u05E9\u05E8\u05D9\u05E8**: \u05EA\u05D7\u05D6\u05D5\u05E7\u05D4 \u05E7\u05DC\u05D4 \u05D1\u05DC\u05D1\u05D3.\n**\u05D9\u05E8\u05D9\u05D3\u05EA \u05DE\u05E9\u05E7\u05DC**: \u05DC\u05D0\u05DB\u05D5\u05DC \u05D1\u05EA\u05D7\u05D6\u05D5\u05E7\u05D4 \u2014 \u05DC\u05DE\u05DC\u05D0 \u05D2\u05DC\u05D9\u05E7\u05D5\u05D2\u05DF.',
