    chat_welcome: '\u05E9\u05DC\u05D5\u05DD. \u05D0\u05E0\u05D9 IronCoach -- \u05D4\u05DE\u05D0\u05DE\u05DF \u05D8\u05E8\u05D9\u05D0\u05EA\u05DC\u05D5\u05DF \u05E9\u05DC\u05DA. \u05E9\u05D0\u05DC \u05D0\u05D5\u05EA\u05D9 \u05DB\u05DC \u05D3\u05D1\u05E8 \u05E2\u05DC \u05D0\u05D9\u05DE\u05D5\u05E0\u05D9\u05DD, \u05D4\u05DB\u05E0\u05D4 \u05DC\u05EA\u05D7\u05E8\u05D5\u05EA \u05D0\u05D5 \u05EA\u05D6\u05D5\u05E0\u05D4.',
    'chat_welcome_run-coach': '\u05D4\u05D9\u05D9, \u05D0\u05E0\u05D9 \u05DE\u05D0\u05DE\u05DF \u05D4\u05E8\u05D9\u05E6\u05D4 \u05E9\u05DC\u05DA. \u05E9\u05D0\u05DC \u05D0\u05D5\u05EA\u05D9 \u05E2\u05DC \u05E7\u05E6\u05D1, \u05E7\u05D3\u05E0\u05E1, \u05E1\u05E4\u05DC\u05D9\u05D8\u05D9\u05DD, \u05D0\u05D6\u05D5\u05E8\u05D9 \u05D3\u05D5\u05E4\u05E7, \u05D0\u05D5 \u05DB\u05DC \u05E9\u05D0\u05DC\u05D4 \u05E2\u05DC \u05E8\u05D9\u05E6\u05D4.',
    'chat_welcome_swim-coach': '\u05D4\u05D9\u05D9, \u05D0\u05E0\u05D9 \u05DE\u05D0\u05DE\u05DF \u05D4\u05E9\u05D7\u05D9\u05D9\u05D4 \u05E9\u05DC\u05DA. \u05E9\u05D0\u05DC \u05D0\u05D5\u05EA\u05D9 \u05E2\u05DC \u05D8\u05DB\u05E0\u05D9\u05E7\u05D4, SWOLF, \u05E7\u05E6\u05D1 \u05DC-100 \u05DE\u05D8\u05E8, \u05D0\u05D5 \u05D0\u05D9\u05DE\u05D5\u05DF \u05D1\u05E8\u05D9\u05DB\u05D4/\u05DE\u05D9\u05DD \u05E4\u05EA\u05D5\u05D7\u05D9\u05DD.',
    'chat_welcome_bike-coach': '\u05D4\u05D9\u05D9, \u05D0\u05E0\u05D9 \u05DE\u05D0\u05DE\u05DF \u05D4\u05D0\u05D5\u05E4\u05E0\u05D9\u05D9\u05DD \u05E9\u05DC\u05DA. \u05E9\u05D0\u05DC \u05D0\u05D5\u05EA\u05D9 \u05E2\u05DC \u05D4\u05E1\u05E4\u05E7, \u05E7\u05D3\u05E0\u05E1, \u05D0\u05D6\u05D5\u05E8\u05D9 \u05D3\u05D5\u05E4\u05E7, \u05D8\u05D9\u05E4\u05D5\u05E1\u05D9\u05DD, \u05D0\u05D5 \u05D0\u05D9\u05DE\u05D5\u05DF \u05D0\u05D5\u05E4\u05E0\u05D9\u05D9\u05DD.',
    'chat_welcome_nutrition-coach': '\u05D4\u05D9\u05D9, \u05D0\u05E0\u05D9 \u05DE\u05D0\u05DE\u05DF \u05D4\u05EA\u05D6\u05D5\u05E0\u05D4 \u05E9\u05DC\u05DA. \u05E9\u05D0\u05DC \u05D0\u05D5\u05EA\u05D9 \u05E2\u05DC \u05D3\u05DC\u05E7, \u05EA\u05D6\u05DE\u05D5\u05DF \u05D0\u05E8\u05D5\u05D7\u05D5\u05EA, \u05EA\u05D6\u05D5\u05E0\u05D4 \u05DC\u05EA\u05D7\u05E8\u05D5\u05EA, \u05D0\u05D5 \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA.',
    chat_storage: '\u05D0\u05D7\u05E1\u05D5\u05DF',
    chat_storage_tip: '**\u05D0\u05D7\u05E1\u05D5\u05DF \u05E6\u05F3\u05D0\u05D8**\n\u05D2\u05D5\u05D3\u05DC \u05DB\u05DC \u05D4\u05D4\u05D5\u05D3\u05E2\u05D5\u05EA \u05E9\u05DC\u05DA \u05D1\u05DE\u05E1\u05D3 \u05D4\u05E0\u05EA\u05D5\u05E0\u05D9\u05DD.\n\u05DB\u05E9\u05D4\u05D0\u05D7\u05E1\u05D5\u05DF \u05DE\u05D2\u05D9\u05E2 \u05DC\u05DE\u05D2\u05D1\u05DC\u05D4 (100 MB), **\u05E1\u05E9\u05E0\u05D9\u05DD \u05D9\u05E9\u05E0\u05D9\u05DD \u05E0\u05DE\u05D7\u05E7\u05D9\u05DD \u05D0\u05D5\u05D8\u05D5\u05DE\u05D8\u05D9\u05EA**.\n\n**\u05D2\u05D5\u05D3\u05DC \u05E1\u05E9\u05E0\u05D9\u05DD:**\n\u05D9\u05E8\u05D5\u05E7 = \u05EA\u05E7\u05D9\u05DF, \u05E6\u05D4\u05D5\u05D1 = \u05D2\u05D3\u05DC (>200 KB), \u05D0\u05D3\u05D5\u05DD = \u05D2\u05D3\u05D5\u05DC \u05DE\u05D0\u05D5\u05D3 (>400 KB).\n\u05E1\u05E9\u05E0\u05D9\u05DD \u05D2\u05D3\u05D5\u05DC\u05D9\u05DD \u05DE\u05D0\u05D8\u05D9\u05DD \u05D0\u05EA \u05D4\u05EA\u05D2\u05D5\u05D1\u05D5\u05EA \u2014 \u05DE\u05D5\u05DE\u05DC\u05E5 \u05DC\u05E4\u05EA\u05D5\u05D7 \u05E1\u05E9\u05DF \u05D7\u05D3\u05E9.',
