    overview_total_hours: '\u05E1\u05D4\u05F4\u05DB \u05E9\u05E2\u05D5\u05EA',
    overview_avg_hr: '\u05D3\u05D5\u05E4\u05E7 \u05DE\u05DE\u05D5\u05E6\u05E2',
    latest_insight: '\u05EA\u05D5\u05D1\u05E0\u05D4 \u05D0\u05D7\u05E8\u05D5\u05E0\u05D4',
    overview_calories: '\u05E7\u05DC\u05D5\u05E8\u05D9\u05D5\u05EA',
    overview_recovery_status: '\u05DE\u05E6\u05D1 \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA',
    overview_recovery_status_tip: '**\u05DE\u05D5\u05DB\u05E0\u05D5\u05EA \u05DC\u05D0\u05D9\u05DE\u05D5\u05DF \u05E7\u05E9\u05D4 \u05D4\u05D9\u05D5\u05DD**\n80-100% = \u05E8\u05E2\u05E0\u05DF \u2014 \u05D0\u05D9\u05DE\u05D5\u05E0\u05D9 \u05DE\u05E4\u05EA\u05D7 (\u05D0\u05D9\u05E0\u05D8\u05E8\u05D5\u05D5\u05DC\u05D9\u05DD, \u05E8\u05D9\u05E6\u05D5\u05EA \u05D0\u05E8\u05D5\u05DB\u05D5\u05EA)\n60-80% = \u05D1\u05D9\u05E0\u05D5\u05E0\u05D9 \u2014 \u05E2\u05D1\u05D5\u05D3\u05D4 \u05E7\u05D1\u05D5\u05E2\u05D4 \u05D1\u05E1\u05D3\u05E8\n40-60% = \u05E2\u05D9\u05D9\u05E3 \u2014 \u05E8\u05E7 \u05D0\u05D9\u05DE\u05D5\u05DF \u05E7\u05DC\n\u05DE\u05EA\u05D7\u05EA 40% = \u05D9\u05D5\u05DD \u05DE\u05E0\u05D5\u05D7\u05D4\n\n**\u05D0\u05D9\u05DA \u05D6\u05D4 \u05E2\u05D5\u05D1\u05D3**\n\u05DB\u05DC \u05D0\u05D9\u05DE\u05D5\u05DF \u05DE\u05D9\u05D9\u05E6\u05E8 \u05E6\u05D9\u05D5\u05DF TRIMP (\u05DE\u05E9\u05DA x \u05E2\u05D5\u05E6\u05DE\u05EA HR).\n\u05E2\u05D9\u05D9\u05E4\u05D5\u05EA (ATL) = \u05DE\u05DE\u05D5\u05E6\u05E2 7 \u05D9\u05DE\u05D9\u05DD \u2014 \u05E2\u05D5\u05DC\u05D4 \u05DE\u05D4\u05E8, \u05D9\u05D5\u05E8\u05D3 \u05DE\u05D4\u05E8.\n\u05DB\u05D5\u05E9\u05E8 (CTL) = \u05DE\u05DE\u05D5\u05E6\u05E2 42 \u05D9\u05DE\u05D9\u05DD \u2014 \u05E0\u05D1\u05E0\u05D4 \u05DC\u05D0\u05D8, \u05D9\u05D5\u05E8\u05D3 \u05DC\u05D0\u05D8.\n\n**\u05E0\u05D5\u05E1\u05D7\u05D4**\nRecovery = 50 + (Fitness - Fatigue) x 0.7\n\u05D1\u05E1\u05D9\u05E1 (\u05DC\u05DC\u05D0 \u05D0\u05D9\u05DE\u05D5\u05DF) = 50%\n\u05DE\u05E0\u05D5\u05D7\u05D4 \u2192 \u05E2\u05D9\u05D9\u05E4\u05D5\u05EA \u05D9\u05D5\u05E8\u05D3\u05EA \u05DE\u05D4\u05E8 \u2192 \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA \u05E2\u05D5\u05DC\u05D4\n\u05D0\u05D9\u05DE\u05D5\u05DF \u05E7\u05E9\u05D4 \u2192 \u05E2\u05D9\u05D9\u05E4\u05D5\u05EA \u05E7\u05D5\u05E4\u05E6\u05EA \u2192 \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA \u05D9\u05D5\u05E8\u05D3\u05EA',
    overview_fitness: '\u05DB\u05D5\u05E9\u05E8',
    overview_fatigue: '\u05E2\u05D9\u05D9\u05E4\u05D5\u05EA',
    overview_fitness_tip: '**\u05DB\u05D5\u05E9\u05E8 (CTL)**\n\u05DE\u05DE\u05D5\u05E6\u05E2 \u05E0\u05E2 42 \u05D9\u05DE\u05D9\u05DD \u05E9\u05DC TRIMP \u05D9\u05D5\u05DE\u05D9.\n\u05D4\u05F4\u05D7\u05E9\u05D1\u05D5\u05DF \u05D1\u05E0\u05E7\u05F4 \u05D4\u05D0\u05D9\u05E8\u05D5\u05D1\u05D9 \u05E9\u05DC\u05DA.\n\n**\u05D0\u05DE\u05D5\u05EA \u05DE\u05D9\u05D3\u05D4**\n40-60 = \u05D1\u05E1\u05D9\u05E1 \u05D7\u05D5\u05D1\u05D1\u05E0\u05D9 \u05D8\u05D5\u05D1\n60-80 = \u05DE\u05D0\u05D5\u05DE\u05DF \u05D4\u05D9\u05D8\u05D1\n80+ = \u05EA\u05D7\u05E8\u05D5\u05EA\u05D9\n\n\u05E2\u05D5\u05DC\u05D4 ~1-2 \u05E0\u05E7\u05D5\u05D3\u05D5\u05EA/\u05E9\u05D1\u05D5\u05E2 \u05E2\u05DD \u05D0\u05D9\u05DE\u05D5\u05DF \u05E2\u05E7\u05D1\u05D9.\n\u05D9\u05E8\u05D9\u05D3\u05D5\u05EA \u05D7\u05D3\u05D5\u05EA = \u05D9\u05D5\u05EA\u05E8 \u05DE\u05D3\u05D9 \u05D4\u05E4\u05E1\u05E7\u05D4.',
    overview_fatigue_tip: '**\u05E2\u05D9\u05D9\u05E4\u05D5\u05EA (ATL)**\n\u05DE\u05DE\u05D5\u05E6\u05E2 \u05E0\u05E2 7 \u05D9\u05DE\u05D9\u05DD \u05E9\u05DC TRIMP \u05D9\u05D5\u05DE\u05D9.\n\u05DE\u05E9\u05E7\u05E3 \u05D0\u05EA \u05E2\u05D5\u05DE\u05E1 \u05D4\u05D0\u05D9\u05DE\u05D5\u05DF \u05D4\u05D0\u05D7\u05E8\u05D5\u05DF.\n\n**\u05D0\u05D9\u05DA \u05DC\u05E7\u05E8\u05D5\u05D0**\n\u05DE\u05E2\u05DC \u05D4\u05DB\u05D5\u05E9\u05E8 = \u05E9\u05DC\u05D1 \u05D4\u05E2\u05DE\u05E1\u05D4, \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA \u05D9\u05D5\u05E8\u05D3\u05EA\n\u05DE\u05EA\u05D7\u05EA \u05D4\u05DB\u05D5\u05E9\u05E8 = \u05E0\u05D7, \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA \u05E2\u05D5\u05DC\u05D4\n\n\u05DB\u05D3\u05D0\u05D9 \u05E9\u05E2\u05D9\u05D9\u05E4\u05D5\u05EA \u05EA\u05E2\u05DC\u05D4 \u05E2\u05DC \u05D4\u05DB\u05D5\u05E9\u05E8 \u05E8\u05E7 2-3 \u05E9\u05D1\u05D5\u05E2\u05D5\u05EA \u05DC\u05E4\u05E0\u05D9 \u05E9\u05D1\u05D5\u05E2 \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA.',
    overview_recovery_tip: '**\u05DC\u05E4\u05E0\u05D9 \u2192 \u05D0\u05D7\u05E8\u05D9**\n\u05DC\u05E4\u05E0\u05D9 % = \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA \u05DC\u05E4\u05E0\u05D9 \u05D4\u05D0\u05D9\u05DE\u05D5\u05DF.\n\u05D0\u05D7\u05E8\u05D9 % = \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA \u05E9\u05E0\u05D5\u05EA\u05E8\u05D4 \u05D0\u05D7\u05E8\u05D9 \u05D4\u05D0\u05D9\u05DE\u05D5\u05DF.\n\n**\u05DE\u05D4 \u05D4\u05D9\u05E8\u05D9\u05D3\u05D4 \u05D0\u05D5\u05DE\u05E8\u05EA**\n\u05D9\u05E8\u05D9\u05D3\u05D4 \u05D2\u05D3\u05D5\u05DC\u05D4 (80% \u2192 45%) = \u05D0\u05D9\u05DE\u05D5\u05DF \u05DE\u05D0\u05D5\u05D3 \u05DE\u05D0\u05EA\u05D2\u05E8\n\u05D9\u05E8\u05D9\u05D3\u05D4 \u05E7\u05D8\u05E0\u05D4 (75% \u2192 65%) = \u05D0\u05D9\u05DE\u05D5\u05DF \u05E7\u05DC\n\u05DC\u05E4\u05E0\u05D9 \u05DB\u05D1\u05E8 \u05DE\u05EA\u05D7\u05EA 50% = \u05D4\u05D9\u05D4 \u05E6\u05E8\u05D9\u05DA \u05DC\u05E0\u05D5\u05D7',
    overview_recovery_training_load: '\u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA \u05D5\u05E2\u05D5\u05DE\u05E1 \u05D0\u05D9\u05DE\u05D5\u05DF',
    overview_recovery_chart_tip: '**\u05DE\u05D3\u05E8\u05D9\u05DA \u05DC\u05D2\u05E8\u05E3**\n\u05E7\u05D5 \u05D9\u05E8\u05D5\u05E7 (Recovery %) = \u05DE\u05D5\u05DB\u05E0\u05D5\u05EA \u05D9\u05D5\u05DE\u05D9\u05EA. \u05D0\u05D9\u05DE\u05D5\u05E0\u05D9 \u05DE\u05E4\u05EA\u05D7 \u05DE\u05E2\u05DC 70%.\n\u05E7\u05D5 \u05DB\u05D7\u05D5\u05DC \u05DE\u05E0\u05D5\u05E7\u05D3 (Fitness/CTL) = \u05E6\u05E8\u05D9\u05DA \u05DC\u05E2\u05DC\u05D5\u05EA \u05DC\u05D0\u05D5\u05E8\u05DA \u05E9\u05D1\u05D5\u05E2\u05D5\u05EA.\n\u05E7\u05D5 \u05D0\u05D3\u05D5\u05DD \u05DE\u05E0\u05D5\u05E7\u05D3 (Fatigue/ATL) = \u05E7\u05D5\u05E4\u05E5 \u05D0\u05D7\u05E8\u05D9 \u05D0\u05D9\u05DE\u05D5\u05DF \u05E7\u05E9\u05D4.\n\u05E2\u05DE\u05D5\u05D3\u05D5\u05EA \u05DB\u05D7\u05D5\u05DC\u05D5\u05EA = TRIMP \u05D9\u05D5\u05DE\u05D9 (\u05E2\u05D5\u05DE\u05E1 \u05D0\u05D9\u05DE\u05D5\u05DF).\n\n**\u05D3\u05E4\u05D5\u05E1 \u05D1\u05E8\u05D9\u05D0**\n2-3 \u05E9\u05D1\u05D5\u05E2\u05D5\u05EA \u05E9\u05DC \u05D4\u05E2\u05DE\u05E1\u05D4, \u05D5\u05D0\u05D6 \u05E9\u05D1\u05D5\u05E2 \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA \u05E9\u05D1\u05D5 \u05E2\u05D9\u05D9\u05E4\u05D5\u05EA \u05D9\u05D5\u05E8\u05D3\u05EA \u05D5\u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA \u05E2\u05D5\u05DC\u05D4.',
    overview_recent_workouts: '\u05D0\u05D9\u05DE\u05D5\u05E0\u05D9\u05DD \u05D0\u05D7\u05E8\u05D5\u05E0\u05D9\u05DD',
    overview_weekly_volume: '\u05E0\u05E4\u05D7 \u05D0\u05D9\u05DE\u05D5\u05DF \u05E9\u05D1\u05D5\u05E2\u05D9 (\u05E9\u05E2\u05D5\u05EA)',
    overview_weekly_volume_tip: '**\u05E0\u05E4\u05D7 \u05E9\u05D1\u05D5\u05E2\u05D9**\n\u05E9\u05E2\u05D5\u05EA \u05DE\u05E6\u05D8\u05D1\u05E8\u05D5\u05EA \u05DC\u05E4\u05D9 \u05E2\u05E0\u05E3 \u05DC\u05DB\u05DC \u05E9\u05D1\u05D5\u05E2.\n\n**\u05DE\u05D4 \u05DC\u05D7\u05E4\u05E9**\n\u05E2\u05DC\u05D9\u05D9\u05D4 \u05E2\u05E7\u05D1\u05D9\u05EA \u05E2\u05DD \u05E9\u05D1\u05D5\u05E2\u05D5\u05EA \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA \u05DB\u05DC 3-4 \u05E9\u05D1\u05D5\u05E2\u05D5\u05EA.\n\u05D1\u05DC\u05D5\u05E7 \u05D1\u05E0\u05D9\u05D9\u05D4 \u05D8\u05D5\u05D1 \u05DC-70.3 \u05DE\u05E2\u05DC\u05D4 \u05E0\u05E4\u05D7 ~10%/\u05E9\u05D1\u05D5\u05E2.\n\u05E9\u05D1\u05D5\u05E2\u05D5\u05EA \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA \u05E6\u05E8\u05D9\u05DB\u05D5\u05EA \u05DC\u05E8\u05D3\u05EA \u05DC~60% \u05DE\u05E0\u05E4\u05D7 \u05D4\u05E9\u05D9\u05D0.',
    overview_workout_distribution: '\u05D4\u05EA\u05E4\u05DC\u05D2\u05D5\u05EA \u05D0\u05D9\u05DE\u05D5\u05E0\u05D9\u05DD',
