    readiness_tip_tsb: '**\u05DE\u05D0\u05D6\u05DF \u05D0\u05D9\u05DE\u05D5\u05DF \u2014 30%** (Banister 1991)\n\u05DB\u05D5\u05E9\u05E8 \u05E4\u05D7\u05D5\u05EA \u05E2\u05D9\u05D9\u05E4\u05D5\u05EA (CTL - ATL).\n\u05D7\u05D9\u05D5\u05D1\u05D9 = \u05E0\u05D7. \u05E9\u05DC\u05D9\u05DC\u05D9 = \u05DE\u05EA\u05D0\u05DE\u05DF \u05E7\u05E9\u05D4.\n\u05EA\u05DE\u05D9\u05D3 \u05D6\u05DE\u05D9\u05DF \u2014 \u05D4\u05D1\u05E1\u05D9\u05E1 \u05DC\u05DE\u05D5\u05DB\u05E0\u05D5\u05EA.\n\u05D9\u05E2\u05D3 \u05D9\u05D5\u05DD \u05DE\u05E8\u05D5\u05E5: 75+.',
    readiness_tip_rhr: '**\u05D3\u05D5\u05E4\u05E7 \u05DE\u05E0\u05D5\u05D7\u05D4 \u2014 15%** (Buchheit 2014)\n\u05DE\u05E9\u05D5\u05D5\u05D4 \u05DC\u05D1\u05E1\u05D9\u05E1 14 \u05D9\u05D5\u05DD.\n\u05E0\u05DE\u05D5\u05DA \u05D9\u05D5\u05EA\u05E8 = \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA \u05D8\u05D5\u05D1\u05D4 \u05D9\u05D5\u05EA\u05E8.\n5+ bpm \u05DE\u05E2\u05DC \u05D4\u05D1\u05E1\u05D9\u05E1 = \u05D3\u05D2\u05DC \u05D0\u05D3\u05D5\u05DD \u05DC\u05D0\u05D9\u05DE\u05D5\u05DF \u05D9\u05EA\u05E8.',
    readiness_tip_hrv: '**\u05DE\u05D2\u05DE\u05EA HRV \u2014 25%** (Plews et al. 2013)\nHRV \u05DE\u05DE\u05D5\u05E6\u05E2 7 \u05D9\u05DE\u05D9\u05DD \u05DE\u05D5\u05DC \u05D1\u05E1\u05D9\u05E1 28 \u05D9\u05D5\u05DD.\nHRV \u05D2\u05D1\u05D5\u05D4 = \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA \u05E4\u05E8\u05E1\u05D9\u05DE\u05E4\u05EA\u05D9\u05EA \u05D8\u05D5\u05D1\u05D4.\n\u05D4\u05D1\u05D9\u05D5\u05DE\u05E8\u05E7\u05E8 \u05D4\u05D7\u05D6\u05E7 \u05D1\u05D9\u05D5\u05EA\u05E8 \u05DC\u05DE\u05D5\u05DB\u05E0\u05D5\u05EA \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA.',
    readiness_tip_sleep: '**\u05D0\u05D9\u05DB\u05D5\u05EA \u05E9\u05D9\u05E0\u05D4 \u2014 20%** (Halson 2014)\n\u05DC\u05E4\u05D9 \u05E9\u05E2\u05D5\u05EA \u05E9\u05D9\u05E0\u05D4 \u05DE-Apple Watch.\n7-9 \u05E9\u05E2\u05D5\u05EA \u05D0\u05D5\u05E4\u05D8\u05D9\u05DE\u05DC\u05D9 \u05DC\u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA.\n\u05E9\u05D9\u05E0\u05D4 = \u05DB\u05DC\u05D9 \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA #1. \u05E4\u05D7\u05D5\u05EA \u05DE-6 \u05E9\u05E2\u05D5\u05EA + \u05D0\u05D9\u05DE\u05D5\u05DF \u05E7\u05E9\u05D4 = \u05E1\u05D9\u05DB\u05D5\u05DF \u05E4\u05E6\u05D9\u05E2\u05D4.',
    readiness_tip_load: '**\u05D9\u05D7\u05E1 \u05E2\u05D5\u05DE\u05E1 \u2014 10%** (Gabbett 2016)\n\u05D9\u05D7\u05E1 \u05E2\u05D5\u05DE\u05E1 \u05D7\u05D3/\u05DB\u05E8\u05D5\u05E0\u05D9 (ATL/CTL).\n0.8-1.3 = \u05D0\u05D6\u05D5\u05E8 \u05D1\u05D8\u05D5\u05D7. >1.5 = \u05E1\u05D9\u05DB\u05D5\u05DF \u05E4\u05E6\u05D9\u05E2\u05D4.\n\u05E9\u05D5\u05DE\u05E8 \u05E2\u05DC \u05E7\u05E4\u05D9\u05E6\u05D5\u05EA \u05E2\u05D5\u05DE\u05E1.',

