    detail_hr_summary: '\u05E1\u05D9\u05DB\u05D5\u05DD \u05D3\u05D5\u05E4\u05E7',
    detail_elev_summary: '\u05E1\u05D9\u05DB\u05D5\u05DD \u05D2\u05D5\u05D1\u05D4',
    detail_total_ascent: '\u05E2\u05DC\u05D9\u05D9\u05D4 \u05DB\u05D5\u05DC\u05DC\u05EA',
    detail_total_descent: '\u05D9\u05E8\u05D9\u05D3\u05D4 \u05DB\u05D5\u05DC\u05DC\u05EA',
    detail_min_elev: '\u05D2\u05D5\u05D1\u05D4 \u05DE\u05D9\u05E0\u05D9\u05DE\u05DC\u05D9',
    detail_max_elev: '\u05D2\u05D5\u05D1\u05D4 \u05DE\u05E7\u05E1\u05D9\u05DE\u05DC\u05D9',
    detail_no_detailed_data: '\u05D0\u05D9\u05DF \u05E0\u05EA\u05D5\u05E0\u05D9\u05DD \u05DE\u05E4\u05D5\u05E8\u05D8\u05D9\u05DD \u05DC\u05D0\u05D9\u05DE\u05D5\u05DF \u05D6\u05D4',
    info_intervals: '**\u05D0\u05D9\u05E0\u05D8\u05E8\u05D5\u05D5\u05DC\u05D9\u05DD \u05DE\u05D6\u05D5\u05D4\u05D9\u05DD** (\u05D7\u05D9\u05E9\u05D5\u05D1 IronCoach)\n\u05DE\u05E0\u05EA\u05D7 \u05E0\u05EA\u05D5\u05E0\u05D9 \u05DE\u05D4\u05D9\u05E8\u05D5\u05EA \u05DE-Apple Health \u05DC\u05D6\u05D9\u05D4\u05D5\u05D9 \u05D3\u05E4\u05D5\u05E1\u05D9 \u05E2\u05D1\u05D5\u05D3\u05D4/\u05DE\u05E0\u05D5\u05D7\u05D4.\nApple Health \u05DE\u05E7\u05DC\u05D9\u05D8 \u05D0\u05EA \u05D4\u05E0\u05EA\u05D5\u05E0\u05D9\u05DD \u05D4\u05D2\u05D5\u05DC\u05DE\u05D9\u05D9\u05DD \u2014 IronCoach \u05DE\u05D6\u05D4\u05D4 \u05D0\u05EA \u05D4\u05D0\u05D9\u05E0\u05D8\u05E8\u05D5\u05D5\u05DC\u05D9\u05DD.\n\n**\u05E2\u05D1\u05D5\u05D3\u05D4** = \u05DE\u05D4\u05D9\u05E8\u05D5\u05EA \u2265 80% \u05DE\u05D4\u05E7\u05E6\u05D1 \u05D4\u05DE\u05DE\u05D5\u05E6\u05E2\n**\u05DE\u05E0\u05D5\u05D7\u05D4** = \u05DE\u05D4\u05D9\u05E8\u05D5\u05EA < 80% (\u05D4\u05DC\u05D9\u05DB\u05D4, \u05E2\u05E6\u05D9\u05E8\u05D5\u05EA, \u05D4\u05EA\u05D0\u05D5\u05E9\u05E9\u05D5\u05EA)\n\n\u05D6\u05D9\u05D4\u05D5\u05D9 \u05DE\u05E9\u05EA\u05DE\u05E9 \u05D1\u05D4\u05D7\u05DC\u05E7\u05EA 10 \u05E9\u05E0\u05D9\u05D5\u05EA \u05DC\u05E1\u05D9\u05E0\u05D5\u05DF \u05E8\u05E2\u05E9. \u05D0\u05D9\u05E0\u05D8\u05E8\u05D5\u05D5\u05DC\u05D9\u05DD \u05E7\u05E6\u05E8\u05D9\u05DD \u05DE-10 \u05E9\u05E0\u05D9\u05D5\u05EA \u05DE\u05DE\u05D5\u05D6\u05D2\u05D9\u05DD.',
