    detail_hr_zone_dist: '\u05D4\u05EA\u05E4\u05DC\u05D2\u05D5\u05EA \u05D0\u05D6\u05D5\u05E8\u05D9 \u05D3\u05D5\u05E4\u05E7',
    detail_pace_per_split: '\u05E7\u05E6\u05D1 \u05DC\u05E4\u05D9 \u05E1\u05E4\u05DC\u05D9\u05D8',
    detail_speed_per_split: '\u05DE\u05D4\u05D9\u05E8\u05D5\u05EA \u05DC\u05E4\u05D9 \u05E1\u05E4\u05DC\u05D9\u05D8',
    detail_elev_gain: '\u05E2\u05DC\u05D9\u05D9\u05EA \u05D2\u05D5\u05D1\u05D4',
    trimp_label: 'TRIMP',
    hrtss_label: 'hrTSS',
    info_trimp_workout: '**TRIMP (עומס אימון)**\nעומס אימון כולל = משך × עוצמת דופק.\nדופק גבוה יותר תורם עומס גבוה באופן אקספוננציאלי.\n\n[dot:#c3e88d] < 50 — קל\n[dot:#ffc777] 50–100 — בינוני\n[dot:#ff966c] 100–150 — קשה\n[dot:#ff5370] 150+ — קשה מאוד',
    info_hrtss_workout: '**hrTSS (ציון עומס לפי דופק)**\nלחץ אימון ביחס לסף הלקטט שלך (LTHR).\n100 = שעה אחת בעוצמת סף.\n\n[dot:#82aaff] < 40 — קל\n[dot:#ffc777] 40–80 — בינוני\n[dot:#ff966c] 80–120 — סף\n[dot:#ff5370] 120+ — קשה\n\nניתן להשוואה בין ענפים — שחייה/אופניים/ריצה באותו סולם.',
